import os

def batch_analyse(directory):
    """Analyse all images in a directory."""
    results = []
    image_exts = {'.jpg', '.jpeg', '.tiff', '.tif'}

    for dirpath, _, filenames in os.walk(directory):
        for fname in filenames:
            ext = os.path.splitext(fname)[1].lower()
            if ext in image_exts:
                fpath = os.path.join(dirpath, fname)
                # In real code: extract_exif(fpath)
                results.append({
                    'file': fname,
                    'path': fpath,
                    'size': os.path.getsize(fpath),
                    # 'exif': extract_exif(fpath)
                })

    return results

# Usage: results = batch_analyse('/evidence/photos')

# Privacy analysis of a photo collection
def privacy_audit(photos):
    """Assess what a collection of photos reveals."""
    locations = set()
    devices = set()
    times = []

    for photo in photos:
        if 'gps' in photo:
            locations.add(photo['gps'])
        if 'device' in photo:
            devices.add(photo['device'])
        if 'datetime' in photo:
            times.append(photo['datetime'])

    print(f"Unique locations visited: {len(locations)}")
    print(f"Devices identified: {len(devices)}")
    if times:
        print(f"Earliest photo: {min(times)}")
        print(f"Latest photo:   {max(times)}")
    print(f"\nThis collection reveals:")
    if len(locations) > 5:
        print("  - Detailed movement pattern!")
    if any('home' in str(l).lower() for l in locations):
        print("  - Possible home location!")

