# Photo Forgery Detector — find metadata inconsistencies

def detect_forgery(exif_data, file_size):
    """Analyse EXIF for signs of forgery or manipulation."""
    findings = []
    risk_score = 0

    # Check 1: DateTime vs DateTimeOriginal mismatch
    dt = exif_data.get('DateTime', '')
    dto = exif_data.get('DateTimeOriginal', '')
    if dt and dto and dt != dto:
        findings.append({
            'check': 'Timestamp Mismatch',
            'detail': f'Modified: {dt} vs Original: {dto}',
            'risk': 'HIGH'
        })
        risk_score += 3

    # Check 2: Software suggests editing
    sw = exif_data.get('Software', '')
    editors = ['Photoshop', 'GIMP', 'Lightroom', 'Snapseed', 'FaceApp']
    for editor in editors:
        if editor.lower() in sw.lower():
            findings.append({
                'check': 'Editing Software',
                'detail': f'Software: {sw}',
                'risk': 'MEDIUM'
            })
            risk_score += 2
            break

    # Check 3: Missing Make/Model (stripped?)
    if not exif_data.get('Make') and not exif_data.get('Model'):
        findings.append({
            'check': 'No Camera Info',
            'detail': 'Make and Model missing — metadata may be stripped',
            'risk': 'MEDIUM'
        })
        risk_score += 2

    # Check 4: Resolution vs file size anomaly
    width = exif_data.get('ImageWidth', 0)
    height = exif_data.get('ImageLength', 0)
    if width and height and file_size > 0:
        pixels = width * height
        bytes_per_pixel = file_size / pixels if pixels > 0 else 0
        # Normal JPEG: 0.5-4 bytes per pixel
        if bytes_per_pixel > 5:
            findings.append({
                'check': 'Unusual Compression',
                'detail': f'{bytes_per_pixel:.1f} bytes/pixel (normal: 0.5-4)',
                'risk': 'LOW'
            })
            risk_score += 1

    # Check 5: GPS present but no camera info
    if exif_data.get('GPSInfo') and not exif_data.get('Make'):
        findings.append({
            'check': 'GPS without Camera',
            'detail': 'GPS data present but camera info missing — possibly injected',
            'risk': 'HIGH'
        })
        risk_score += 3

    # Overall assessment
    if risk_score >= 5:
        verdict = 'LIKELY MANIPULATED'
    elif risk_score >= 3:
        verdict = 'SUSPICIOUS'
    elif risk_score >= 1:
        verdict = 'MINOR ANOMALIES'
    else:
        verdict = 'APPEARS AUTHENTIC'

    return {'verdict': verdict, 'score': risk_score, 'findings': findings}

