# EXIF Comparison Tool — are two photos from the same device?

def compare_exif(exif1, exif2, name1='Photo A', name2='Photo B'):
    """Compare two EXIF datasets and find similarities/differences."""
    compare_fields = [
        ('Make', 'Camera manufacturer'),
        ('Model', 'Camera model'),
        ('Software', 'Software/firmware'),
        ('LensModel', 'Lens'),
        ('BodySerialNumber', 'Serial number'),
        ('ImageWidth', 'Width'),
        ('ImageLength', 'Height'),
    ]

    matches = []
    differences = []
    missing = []

    for field, desc in compare_fields:
        v1 = exif1.get(field)
        v2 = exif2.get(field)

        if v1 is None and v2 is None:
            missing.append(field)
        elif v1 == v2:
            matches.append((field, desc, v1))
        else:
            differences.append((field, desc, v1, v2))

    # Determine linkage probability
    match_count = len(matches)
    total = len(compare_fields) - len(missing)
    if total > 0:
        match_pct = match_count / total * 100
    else:
        match_pct = 0

    if match_pct >= 80:
        linkage = 'LIKELY SAME DEVICE'
    elif match_pct >= 50:
        linkage = 'POSSIBLE SAME DEVICE'
    else:
        linkage = 'DIFFERENT DEVICES'

    return {
        'linkage': linkage,
        'match_pct': match_pct,
        'matches': matches,
        'differences': differences,
        'missing': missing
    }

